#include <bits/stdc++.h>
using namespace std;vector<int>p;
int f(int x){return p[x]==x?x:p[x]=f(p[x]);}
int main(){int n,m;scanf("%d %d",&n,&m);p.resize(n);for(int i=0;i<n;i++)p[i]=i;int ans=0;for(int i=1;i<=m;i++){int a,b;scanf("%d %d",&a,&b);if(ans)continue;if(f(a)==f(b)){ans=i;}else p[f(a)]=f(b);}printf("%d\n",ans);}
